const numbersToWords=E=>{const X=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(E<0x14)return X[E];if(E<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](E/0xa)]+(E%0xa?'\x20'+X[E%0xa]:'');if(E<0x3e8){const Z=Math['floor'](E/0x64),a=E%0x64;return(0x1===Z?'εκατό':0x2===Z?'διακόσια':0x3===Z?'τριακόσια':0x4===Z?'τετρακόσια':0x5===Z?'πεντακόσια':0x6===Z?'εξακόσια':0x7===Z?'επτακόσια':0x8===Z?'οκτακόσια':0x9===Z?'εννιακόσια':'')+(a?'\x20'+numbersToWords(a):'');}return E<0xf4240?numbersToWords(Math['floor'](E/0x3e8))+'\x20χιλιάδες'+(E%0x3e8?'\x20'+numbersToWords(E%0x3e8):''):numbersToWords(Math['floor'](E/0xf4240))+'\x20εκατομμύρια'+(E%0xf4240?'\x20'+numbersToWords(E%0xf4240):'');},numberToText=(E,X='money')=>{const Z=Math['floor'](E),a=Math['round'](0x64*(E-Z));let H=numbersToWords(Z),B=a>0x0?numbersToWords(a):'';switch(X){case'money':return B?H+'\x20ευρώ\x20και\x20'+B+'\x20λεπτά':H+'\x20ευρώ';case'time':return B?H+'\x20ώρες\x20και\x20'+B+'\x20λεπτά':H+'\x20ώρες';default:return B?H+'\x20και\x20'+B:''+H;}};